import pathlib

total = 0
for file_path in pathlib.Path('.').rglob('*'):
    if file_path.is_file():
        try:
            content = file_path.read_text(encoding='utf-8')
            total += content.count('TODO')
        except (UnicodeDecodeError, PermissionError):
            continue

with open('count.txt', 'w') as f:
    f.write(str(total) + '\n')

